documentation.value:
Writes formatted output to stdout.

```c
printf("Hello %s, age %d\n", name, age);
printf("%.2f\n", 3.14159);
```

Reads formatted input from stdin.

```c
int n;
scanf("%d", &n);
char name[50];
scanf("%49s", name);
```

Writes formatted output to a file stream.

```c
FILE *fp = fopen("log.txt", "w");
fprintf(fp, "Error code: %d\n", code);
fprintf(stderr, "Error: %s\n", msg);
```

Reads formatted input from a file stream.

```c
FILE *fp = fopen("data.txt", "r");
int x;
fscanf(fp, "%d", &x);
```

Writes formatted output to a character string buffer.

```c
char buf[256];
sprintf(buf, "Name: %s, Score: %d", name, score);
```

Writes formatted output to a buffer with a maximum size to prevent overflow.

```c
char buf[64];
snprintf(buf, sizeof(buf), "Value: %d", val);
```

Opens a file and returns a FILE pointer.

```c
FILE *fp = fopen("data.txt", "r");
if (fp == NULL) {
    perror("fopen");
    return 1;
}
```
Modes: "r" read, "w" write, "a" append, "rb" binary read, "wb" binary write.

Reads binary data from a file stream.

```c
char buf[1024];
size_t n = fread(buf, 1, sizeof(buf), fp);
```

Reads a line from a file stream into a buffer.

```c
char line[256];
while (fgets(line, sizeof(line), fp) != NULL) {
    printf("%s", line);
}
```

Tests the end-of-file indicator for a stream.

```c
while (!feof(fp)) {
    fgets(line, sizeof(line), fp);
}
```

Flushes the output buffer of a stream.

```c
fflush(stdout);
fflush(fp);
```

Prints a descriptive error message to stderr based on errno.

```c
FILE *fp = fopen("missing.txt", "r");
if (!fp) {
    perror("fopen");
}
```

Allocates a block of uninitialized memory on the heap.

```c
int *arr = (int *)malloc(n * sizeof(int));
if (arr == NULL) {
    perror("malloc");
    exit(1);
}
free(arr);
```

Allocates memory for an array and initializes all bytes to zero.

```c
int *arr = (int *)calloc(n, sizeof(int));
if (!arr) {
    perror("calloc");
    exit(1);
}
free(arr);
```

Resizes a previously allocated memory block.

```c
int *tmp = (int *)realloc(arr, new_size * sizeof(int));
if (!tmp) {
    perror("realloc");
    free(arr);
    exit(1);
}
arr = tmp;
```

Deallocates previously allocated memory.

```c
free(ptr);
ptr = NULL;
```

Terminates the calling process with the given exit status.

```c
exit(EXIT_SUCCESS);
exit(EXIT_FAILURE);
```

Converts a string to a long integer with error detection.

```c
char *end;
long val = strtol("123abc", &end, 10);
if (*end != '\0') {
    printf("Trailing chars: %s\n", end);
}
```

Converts a string to a double with error detection.

```c
char *end;
double val = strtod("3.14xyz", &end);
```

Sorts an array using a comparison function.

```c
int cmp(const void *a, const void *b) {
    return (*(int *)a - *(int *)b);
}
qsort(arr, n, sizeof(int), cmp);
```

Searches a sorted array for a key using binary search.

```c
int key = 42;
int *found = (int *)bsearch(&key, arr, n, sizeof(int), cmp);
```

Passes a command string to the host command processor.

```c
system("ls -la");
int ret = system("gcc -o out main.c");
```

Returns the value of an environment variable, or NULL if not found.

```c
const char *home = getenv("HOME");
if (home) printf("Home: %s\n", home);
```

Copies a string to a destination buffer. Unsafe — prefer strncpy or snprintf.

```c
char dest[64];
strcpy(dest, "hello");
```

Copies up to n characters from src to dest. May not null-terminate if src is longer.

```c
char dest[64];
strncpy(dest, src, sizeof(dest) - 1);
dest[sizeof(dest) - 1] = '\0';
```

Appends src to the end of dest. Unsafe — prefer strncat.

```c
char buf[128] = "Hello, ";
strcat(buf, "World!");
```

Compares two strings lexicographically. Returns 0 if equal, <0 if s1<s2, >0 if s1>s2.

```c
if (strcmp(a, b) == 0) {
    printf("Strings are equal\n");
}
```

Compares up to n characters of two strings.

```c
if (strncmp(line, "GET ", 4) == 0) {
    // handle GET request
}
```

Returns a pointer to the first occurrence of a character in a string.

```c
char *p = strchr(str, ':');
if (p) printf("Found at index %ld\n", p - str);
```

Finds the first occurrence of a substring within a string.

```c
char *p = strstr(haystack, "needle");
if (p) printf("Found at index %ld\n", p - haystack);
```

Fills n bytes of memory with the specified byte value.

```c
memset(buf, 0, sizeof(buf));
memset(arr, -1, n * sizeof(int));
```

Compares n bytes of two memory blocks.

```c
if (memcmp(buf1, buf2, n) == 0) {
    printf("Buffers are equal\n");
}
```

Conditional execution.

```c
if (condition) {
    // code
}
```

Alternative branch of an if statement.

```c
if (x > 0) {
    // positive
} else {
    // non-positive
}
```

Loop with initialization, condition, and increment.

```c
for (int i = 0; i < n; i++) {
    // body
}
```

Loop that repeats while a condition is true.

```c
while (condition) {
    // body
}
```

Loop that executes at least once.

```c
do {
    // body
} while (condition);
```

Multi-way branch based on an integer expression.

```c
switch (val) {
    case 1: break;
    default: break;
}
```

A case label inside a switch statement.

```c
case 1:
    printf("one\n");
    break;
```

Returns a value from a function.

```c
return 0;
return result;
```

Defines a new name for an existing type.

```c
typedef unsigned long ulong;
typedef struct Node Node;
```

Defines a composite data type.

```c
struct Point {
    int x;
    int y;
};
```

Defines a type where all members share the same memory.

```c
union Data {
    int i;
    float f;
    char str[20];
};
```

Gives a variable static storage or restricts a function/variable to file scope.

```c
static int counter = 0;
static void helper(void) { }
```

Declares a variable or function defined in another translation unit.

```c
extern int global_count;
extern void init(void);
```

Declares a read-only variable.

```c
const int MAX = 100;
const char *msg = "hello";
```

Suggests to the compiler to inline a function for performance.

```c
static inline int max(int a, int b) {
    return a > b ? a : b;
}
```

Unconditional jump to a labeled statement. Often used for cleanup in C.

```c
if (error)
    goto cleanup;
cleanup:
    free(ptr);
```

Includes a header file.

```c
#include <stdio.h>
#include "myheader.h"
```

Standard main function entry point.

```c
int main(int argc, char *argv[]) {
    return 0;
}
```

Creates a typedef'd struct.

```c
typedef struct {
    int x;
    int y;
} Point;
```

Standard for loop iterating from 0 to n.

```c
for (int i = 0; i < n; i++) {
    // body
}
```

A while loop template.

```c
while (condition) {
    // body
}
```

A switch-case template.

```c
switch (expr) {
    case VAL1:
        break;
    case VAL2:
        break;
    default:
        break;
}
```

completions.insertText:
switch (${1:expr}) {
	case ${2:VAL1}:
		${3}
		break;
	case ${4:VAL2}:
		${5}
		break;
	default:
		${6}
		break;
}

