Opens a file, checks for errors, performs I/O, and closes it.

```c
FILE *fp = fopen("file.txt", "r");
if (!fp) { perror("fopen"); return 1; }
// read/write
fclose(fp);
```

completions.insertText:
FILE *${1:fp} = fopen("${2:filename}", "${3:r}");
if (!${1:fp}) {
	perror("fopen");
	return ${4:1};
}
${5:// read/write operations}
fclose(${1:fp});

documentation.value:
Template for defining a function.

```c
int my_func(int param) {
    return 0;
}
```

Creates a typedef'd enum.

```c
typedef enum {
    STATE_INIT,
    STATE_RUNNING,
    STATE_DONE
} State;
```

Defines a singly linked list node.

```c
typedef struct Node {
    int data;
    struct Node *next;
} Node;
```

A do-while loop that runs at least once.

```c
do {
    // body
} while (condition);
```

An if-else block.

```c
if (condition) {
    // true
} else {
    // false
}
```

Splits a string into tokens based on delimiter characters.

```c
char str[] = "one,two,three";
char *tok = strtok(str, ",");
while (tok) {
    printf("%s\n", tok);
    tok = strtok(NULL, ",");
}
```

Tests whether a character is an alphabetic letter.

```c
#include <ctype.h>
if (isalpha(ch)) { /* ... */ }
```

Tests whether a character is a decimal digit.

```c
#include <ctype.h>
if (isdigit(ch)) { /* ... */ }
```

Returns the current calendar time as time_t.

```c
#include <time.h>
time_t now = time(NULL);
printf("%s", ctime(&now));
```

Returns processor time consumed by the program.

```c
clock_t start = clock();
// ... work ...
clock_t end = clock();
double elapsed = (double)(end - start) / CLOCKS_PER_SEC;
```

Aborts the program if the expression is false (in debug builds).

```c
#include <assert.h>
assert(ptr != NULL);
assert(n > 0);
```

Null pointer constant, typically defined as `((void *)0)` or `0`.

```c
int *p = NULL;
if (p == NULL) { /* ... */ }
```

End-of-file constant, typically -1. Used to detect end of input.

```c
int ch;
while ((ch = getchar()) != EOF) {
    putchar(ch);
}
```
